  1→// ═══════════════════════════════════════════════════════════════════════
  2→// AUTH: Token 管理
  3→// ═══════════════════════════════════════════════════════════════════════
  4→const TOKEN_KEY = 'mt-tool-token';
  5→
  6→function getToken() {
  7→  return localStorage.getItem(TOKEN_KEY);
  8→}
  9→
 10→function setToken(token) {
 11→  localStorage.setItem(TOKEN_KEY, token);
 12→}
 13→
 14→function clearToken() {
 15→  localStorage.removeItem(TOKEN_KEY);
 16→}
 17→
 18→function redirectToLogin() {
 19→  // 重定向到后端 OA 登录接口
 20→  window.location.href = '/api/auth/oauth2/login';
 21→}
 22→
 23→// 检查登录状态，未登录则跳转
 24→function requireAuth() {
 25→  if (!getToken()) {
 26→    redirectToLogin();
 27→    return false;
 28→  }
 29→  return true;
 30→}
