 32→// ═══════════════════════════════════════════════════════════════════════
 33→// URL ROUTING: /123/admin.html 或 /123/ 解析文档 ID
 34→// ═══════════════════════════════════════════════════════════════════════
 35→function getDocIdFromUrl() {
 36→  const m = window.location.pathname.match(/^\/(\d+)(\/|\/admin\.html)?$/);
 37→  return m ? parseInt(m[1], 10) : null;
 38→}
 39→
 40→function getPageName() {
 41→  return window.location.pathname.includes('admin') ? 'admin.html' : '';
 42→}
 43→
 44→function buildDocUrl(docId) {
 45→  const page = getPageName();
 46→  return page ? '/' + docId + '/' + page : '/' + docId + '/';
 47→}
 48→
 49→function updateUrlForDoc(docId) {
 50→  const newUrl = buildDocUrl(docId);
 51→  window.history.pushState({ docId }, '', newUrl);
 52→}
 53→
 54→window.addEventListener('popstate', function(e) {
 55→  const id = getDocIdFromUrl();
 56→  if (id && id !== currentDocId) {
 57→    openDocument(id, true);
 58→  }
 59→});
