 61→// ═══════════════════════════════════════════════════════════════════════
 62→// API FETCH (带 JWT 鉴权)
 63→// ═══════════════════════════════════════════════════════════════════════
 64→async function apiFetch(url, options = {}) {
 65→  const headers = { ...options.headers };
 66→  const token = getToken();
 67→  if (token) {
 68→    headers['Authorization'] = 'Bearer ' + token;
 69→  }
 70→  if (options.body && typeof options.body === 'object') {
 71→    headers['Content-Type'] = 'application/json';
 72→    options.body = JSON.stringify(options.body);
 73→  }
 74→  const resp = await fetch(url, { ...options, headers });
 75→
 76→  // 401 未登录 -> 跳转 OA 登录
 77→  if (resp.status === 401) {
 78→    clearToken();
 79→    redirectToLogin();
 80→    throw new Error('未登录');
 81→  }
 82→
 83→  const data = await resp.json();
 84→  if (data.code !== 200) { throw new Error(data.message || '请求失败'); }
 85→  return data.data;
 86→}
