198→// ═══════════════════════════════════════════════════════════════════════
199→// RENDER OUTLINE
200→// ═══════════════════════════════════════════════════════════════════════
201→function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
202→function ea(s){return esc(s).replace(/'/g,'&#39;');}
203→function chevron(){return '<svg class="chevron" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><polyline points="2,4 6,8 10,4"/></svg>';}
204→
205→function renderOutline() {
206→  const panel = document.getElementById('outlinePanel');
207→  let html = '';
208→  acts.forEach(function(act, ai) {
209→    html += '<div class="act'+(act.open?'':' collapsed')+'" id="act-'+ai+'">';
210→    html += '<div class="act-header" onclick="toggleAct('+ai+');selectAct('+ai+')">'+chevron()+esc(act.title)+'</div>';
211→    html += '<div class="act-body'+(act.open?'':' hidden')+'">';
212→    act.chapters.forEach(function(ch, ci) {
213→      html += '<div class="chapter'+(ch.open?'':' collapsed')+'" id="ch-'+ai+'-'+ci+'">';
214→      html += '<div class="chapter-header" onclick="toggleChapter('+ai+','+ci+')">'+chevron()+esc(ch.title)+'</div>';
215→      html += '<div class="chapter-body'+(ch.open?'':' hidden')+'">';
216→      ch.scenes.forEach(function(sc) {
217→        const dotOn = sc.detail ? ' on' : '';
218→        const sel = sc.id === selectedId ? ' selected' : '';
219→        const displayText = sc.summary || sc.body;
220→        const body = displayText ? '<div class="scene-body-text" contenteditable="true" data-id="'+ea(sc.id)+'" onfocus="selectScene(\''+ea(sc.id)+'\')" onblur="onSummaryBlur(this)" onkeydown="handleBodyKey(event)">'+esc(displayText)+'</div>' : '';
221→        html += '<div class="scene-item'+sel+'" data-id="'+ea(sc.id)+'">';
222→        html += '<div class="scene-content">';
223→        html += '<div class="scene-title-row">';
224→        html += '<div class="scene-left"><div class="dot-btn" onclick="selectScene(\''+ea(sc.id)+'\')" title="查看原文"><div class="dot'+dotOn+'" data-dot="'+ea(sc.id)+'"></div></div><span class="scene-id">'+esc(sc.id)+'</span></div>';
225→        html += '<span class="scene-title-text" contenteditable="true" data-id="'+ea(sc.id)+'" data-field="title" onfocus="selectScene(\''+ea(sc.id)+'\')" onblur="onEditBlur(this)" onclick="event.stopPropagation()" onkeydown="handleTitleKey(event)">'+esc(sc.title)+'</span>';
226→        html += '</div>';
227→        html += body+'</div></div>';
228→      });
229→      html += '</div></div>';
230→    });
231→    html += '</div></div>';
232→  });
233→  panel.innerHTML = html;
234→}
235→
236→function onEditBlur(el) {
237→  const id=el.dataset.id, field=el.dataset.field, val=el.innerText;
238→  for(const act of acts) for(const ch of act.chapters) {
239→    const sc=ch.scenes.find(s=>s.id===id); if(sc){sc[field]=val;break;}
240→  }
241→}
242→function handleTitleKey(e){e.stopPropagation();if(e.key==='Enter'){e.preventDefault();e.target.blur();}}
243→function onSummaryBlur(el) {
244→  const id=el.dataset.id, val=el.innerText;
245→  for(const act of acts) for(const ch of act.chapters){
246→    const sc=ch.scenes.find(s=>s.id===id);
247→    if(sc){sc.summary?(sc.summary=val):(sc.body=val);break;}
248→  }
249→}
250→function handleBodyKey(e){e.stopPropagation();if(e.key==='Enter'){e.preventDefault();document.execCommand('insertLineBreak');}}
251→
252→function toggleAct(ai){acts[ai].open=!acts[ai].open;const el=document.getElementById('act-'+ai);el.classList.toggle('collapsed');el.querySelector('.act-body').classList.toggle('hidden');}
253→function toggleChapter(ai,ci){acts[ai].chapters[ci].open=!acts[ai].chapters[ci].open;const el=document.getElementById('ch-'+ai+'-'+ci);el.classList.toggle('collapsed');el.querySelector('.chapter-body').classList.toggle('hidden');}
