255→// ═══════════════════════════════════════════════════════════════════════
256→// SELECT ACT / SCENE
257→// ═══════════════════════════════════════════════════════════════════════
258→function selectAct(ai) {
259→  if(selectedId){const p=document.querySelector('.scene-item[data-id="'+selectedId+'"]');if(p)p.classList.remove('selected');}
260→  selectedId=null;
261→  const act=acts[ai]; if(!act)return;
262→  document.getElementById('sourcePlaceholder').style.display='none';
263→  document.getElementById('sourceInner').classList.add('visible');
264→  document.getElementById('srcId').textContent='ACT';
265→  document.getElementById('srcTitle').textContent=act.title;
266→  const sb=document.getElementById('sourceBody');
267→  sb.contentEditable='true'; sb.textContent=act.notes||''; sb.style.display='block';
268→  document.getElementById('sourceNone').style.display='none';
269→  sb.dataset.actIndex=ai; sb.dataset.mode='act';
270→}
271→
272→function selectScene(id) {
273→  if(selectedId){const p=document.querySelector('.scene-item[data-id="'+selectedId+'"]');if(p)p.classList.remove('selected');}
274→  selectedId=id;
275→  const c=document.querySelector('.scene-item[data-id="'+id+'"]');if(c)c.classList.add('selected');
276→  let title=id, detail='';
277→  outer:for(const act of acts)for(const ch of act.chapters){
278→    const sc=ch.scenes.find(s=>s.id===id);
279→    if(sc){title=sc.title;detail=sc.detail||'';break outer;}
280→  }
281→  document.getElementById('sourcePlaceholder').style.display='none';
282→  document.getElementById('sourceInner').classList.add('visible');
283→  document.getElementById('srcId').textContent=id;
284→  document.getElementById('srcTitle').textContent=title;
285→  const sb=document.getElementById('sourceBody');
286→  sb.contentEditable='true'; sb.textContent=detail; sb.style.display='block';
287→  sb.dataset.mode='scene'; delete sb.dataset.actIndex;
288→  document.getElementById('sourceNone').style.display='none';
289→}
