291→// ═══════════════════════════════════════════════════════════════════════
292→// VIEW
293→// ═══════════════════════════════════════════════════════════════════════
294→function expandLevel(){ if(viewLevel<2){viewLevel++;applyLevel();} }
295→function collapseLevel(){ if(viewLevel>0){viewLevel--;applyLevel();} }
296→function applyLevel(){
297→  const actsOpen = viewLevel>=1;
298→  const chaptersOpen = viewLevel>=2;
299→  acts.forEach(function(act,ai){
300→    act.open=actsOpen;
301→    const el=document.getElementById('act-'+ai); if(!el)return;
302→    el.classList.toggle('collapsed',!actsOpen);
303→    el.querySelector('.act-body').classList.toggle('hidden',!actsOpen);
304→    act.chapters.forEach(function(ch,ci){
305→      ch.open=chaptersOpen;
306→      const cel=document.getElementById('ch-'+ai+'-'+ci); if(!cel)return;
307→      cel.classList.toggle('collapsed',!chaptersOpen);
308→      cel.querySelector('.chapter-body').classList.toggle('hidden',!chaptersOpen);
309→    });
310→  });
311→  document.getElementById('btnExpand').classList.toggle('active',viewLevel===2);
312→  document.getElementById('btnCollapse').classList.toggle('active',viewLevel===0);
313→}
