315→// ═══════════════════════════════════════════════════════════════════════
316→// META
317→// ═══════════════════════════════════════════════════════════════════════
318→function refreshMeta(){
319→  let total=0; acts.forEach(a=>a.chapters.forEach(c=>total+=c.scenes.length));
320→  document.getElementById('topMeta').textContent = total ? total+'个场景' : '—';
321→}
322→
323→// ═══════════════════════════════════════════════════════════════════════
324→// DETAIL EDIT
325→// ═══════════════════════════════════════════════════════════════════════
326→function onDetailBlur() {
327→  const sb=document.getElementById('sourceBody');
328→  const val=sb.innerText;
329→  if(sb.dataset.mode==='act'){
330→    const ai=parseInt(sb.dataset.actIndex);
331→    if(acts[ai]) acts[ai].notes=val;
332→    return;
333→  }
334→  if (!selectedId) return;
335→  outer: for(const act of acts) for(const ch of act.chapters){
336→    const sc=ch.scenes.find(s=>s.id===selectedId);
337→    if(sc){
338→      sc.detail=val;
339→      const dot=document.querySelector('.dot[data-dot="'+selectedId+'"]');
340→      if(dot) dot.classList.toggle('on', !!val.trim());
341→      break outer;
342→    }
343→  }
344→}
