346→// ═══════════════════════════════════════════════════════════════════════
347→// SERIALIZE
348→// ═══════════════════════════════════════════════════════════════════════
349→function serializeOutline() {
350→  const lines=[];
351→  if(fileTitle) lines.push(fileTitle,'');
352→  acts.forEach(act=>{
353→    lines.push('## '+act.title,'');
354→    if(act.notes) lines.push(act.notes,'');
355→    act.chapters.forEach(ch=>{
356→      lines.push('### '+ch.title,'');
357→      ch.scenes.forEach(sc=>{
358→        lines.push('**'+sc.id+'. '+sc.title+'**');
359→        if(sc.summary){
360→          sc.summary.split('\n').forEach(l=>lines.push('> '+l));
361→        } else if(sc.body){
362→          lines.push(sc.body);
363→        }
364→        if(sc.detail){
365→          lines.push('','<details><summary>场景细节</summary>','',sc.detail,'','</details>');
366→        }
367→        lines.push('');
368→      });
369→    });
370→  });
371→  return lines.join('\n');
372→}
