375→// DOC LIST
376→// ═══════════════════════════════════════════════════════════════════════
377→function formatTime(t) {
378→  if (!t) return '';
379→  const d = new Date(t);
380→  return d.toLocaleDateString('zh-CN') + ' ' + d.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });
381→}
