383→async function loadDocList() {
384→  try {
385→    const docs = await apiFetch('/api/doc/list');
386→    const list = document.getElementById('docList');
387→    if (!docs || docs.length === 0) {
388→      list.innerHTML = '<div style="padding:12px;color:var(--text-muted);font-size:11px;text-align:center;">暂无文档</div>';
389→      return;
390→    }
391→    list.innerHTML = docs.map(d =>
392→      `<a class="doc-item${d.id === currentDocId ? ' active' : ''}" href="${buildDocUrl(d.id)}" onclick="event.preventDefault();openDocument(${d.id})" data-doc-id="${d.id}">
393→        ${esc(d.title || '无标题')}
394→        <div class="doc-item-time">${formatTime(d.updatedAt)}</div>
395→      </a>`
396→    ).join('');
397→  } catch (e) {
398→    console.warn('加载文档列表失败:', e);
399→  }
400→}
401→
402→async function openDocument(id, skipPushState) {
403→  try {
404→    showToast('加载中…');
405→    const doc = await apiFetch('/api/doc/' + id);
406→    currentDocId = doc.id;
407→    if (!skipPushState) { updateUrlForDoc(doc.id); }
408→    const text = doc.content || '';
409→    acts = parseOutline(text);
410→    let total = 0; acts.forEach(a => a.chapters.forEach(c => total += c.scenes.length));
411→    const fl = text.split('\n')[0].trim();
412→    if (fl.startsWith('# ')) { fileTitle = fl; document.getElementById('topTitle').textContent = fl.slice(2).trim(); }
413→    else { fileTitle = ''; document.getElementById('topTitle').textContent = doc.title || '大纲编辑器'; }
414→    renderOutline(); refreshMeta(); loadDocList();
415→    showToast('已载入 ' + total + ' 个场景');
416→  } catch (e) {
417→    showToast('加载失败: ' + e.message, true);
418→  }
419→}
420→
421→function autoLoadFromUrl() {
422→  const id = getDocIdFromUrl();
423→  if (id) { openDocument(id, true); }
424→}
