426→// ═══════════════════════════════════════════════════════════════════════
427→// SAVE TO SERVER
428→// ═══════════════════════════════════════════════════════════════════════
429→async function saveToServer() {
430→  if (!acts.length) { showToast('请先导入大纲', true); return; }
431→  const content = serializeOutline();
432→  const title = fileTitle ? fileTitle.slice(2).trim() : '未命名大纲';
433→
434→  try {
435→    showToast('保存中…');
436→    const doc = await apiFetch('/api/doc/save', {
437→      method: 'POST',
438→      body: { id: currentDocId, title, content },
439→    });
440→    const isNew = !currentDocId;
441→    currentDocId = doc.id;
442→    if (isNew) { updateUrlForDoc(doc.id); }
443→    showToast('已保存');
444→    loadDocList();
445→  } catch (e) {
446→    showToast('保存失败: ' + e.message, true);
447→  }
448→}
