450→// ═══════════════════════════════════════════════════════════════════════
451→// EXPORT
452→// ═══════════════════════════════════════════════════════════════════════
453→function exportClean(){
454→  if(!acts.length){showToast('请先导入大纲',true);return;}
455→  const content = serializeOutline();
456→  const name = fileTitle ? fileTitle.slice(2).trim().replace(/[\/\\:*?"<>|]/g,'_') : 'outline';
457→  const a=document.createElement('a');
458→  a.href=URL.createObjectURL(new Blob([content],{type:'text/markdown;charset=utf-8'}));
459→  a.download=name+'.md'; a.click();
460→}
