473→// ═══════════════════════════════════════════════════════════════════════
474→// RESIZER
475→// ═══════════════════════════════════════════════════════════════════════
476→(function(){
477→  const RKEY = 'outline-rpanel-width-v1';
478→  const resizer = document.getElementById('resizer');
479→  const rightPanel = document.getElementById('rightPanel');
480→  const saved = parseInt(localStorage.getItem(RKEY), 10);
481→  if (saved && saved >= 200) rightPanel.style.width = saved + 'px';
482→
483→  let startX, startW;
484→  resizer.addEventListener('mousedown', function(e) {
485→    e.preventDefault();
486→    startX = e.clientX;
487→    startW = rightPanel.offsetWidth;
488→    resizer.classList.add('dragging');
489→    document.body.style.cursor = 'col-resize';
490→    document.body.style.userSelect = 'none';
491→
492→    function onMove(e) {
493→      const delta = startX - e.clientX;
494→      const newW = Math.max(200, Math.min(window.innerWidth * 0.7, startW + delta));
495→      rightPanel.style.width = newW + 'px';
496→    }
497→    function onUp() {
498→      localStorage.setItem(RKEY, parseInt(rightPanel.style.width, 10));
499→      resizer.classList.remove('dragging');
500→      document.body.style.cursor = '';
501→      document.body.style.userSelect = '';
502→      document.removeEventListener('mousemove', onMove);
503→      document.removeEventListener('mouseup', onUp);
504→    }
505→    document.addEventListener('mousemove', onMove);
506→    document.addEventListener('mouseup', onUp);
507→  });
508→})();
