 61→.view-toggle button.active { background:var(--surface3); color:var(--text); }
 62→.btn { background:none; border:1px solid var(--border2); color:var(--text-dim); padding:4px 11px; border-radius:5px; font-size:11px; cursor:pointer; font-family:var(--sans); transition:all .15s; white-space:nowrap; position:relative; }
