 68→.theme-panel { display:none; position:absolute; top:calc(100% + 8px); right:0; background:var(--surface); border:1px solid var(--border2); border-radius:8px; padding:12px; width:230px; z-index:200; box-shadow:0 8px 24px rgba(0,0,0,.4); }
