 85→document.getElementById('importBtn').addEventListener('click', async () => {
 86→  if (window.showOpenFilePicker) {
 87→    try {
 88→      const [handle] = await window.showOpenFilePicker({
 89→        types: [{ description: 'Markdown', accept: {'text/markdown': ['.md','.txt']} }]
 90→      });
 91→      loadFile(await handle.getFile());
 92→    } catch(e) { /* cancelled */ }
 93→  } else {
 94→    document.getElementById('fileInput').click();
 95→  }
 96→});
 97→document.getElementById('fileInput').addEventListener('change', function(e) {
 98→  const f = e.target.files && e.target.files[0]; if (f) loadFile(f); this.value='';
 99→});
100→
101→function loadFile(file) {
102→  showToast('正在读取…');
103→  currentDocId = null;
104→  const reader = new FileReader();
105→  reader.onerror = () => showToast('文件读取失败', true);
106→  reader.onload = function(e) {
107→    try {
108→      const text = e.target.result;
109→      acts = parseOutline(text);
110→      let total = 0; acts.forEach(a=>a.chapters.forEach(c=>total+=c.scenes.length));
111→      if (!total) { showToast('未识别到场景，请确认格式', true); return; }
112→      const fl = text.split('\n')[0].trim();
113→      if (fl.startsWith('# ')) { fileTitle = fl; document.getElementById('topTitle').textContent = fl.slice(2).trim(); }
114→      renderOutline(); refreshMeta();
115→      showToast('已载入 ' + total + ' 个场景');
116→    } catch(err) { showToast('解析出错：' + err.message, true); console.error(err); }
117→  };
118→  reader.readAsText(file, 'UTF-8');
119→}
120→
121→function newDocument() {
122→  acts = [];
123→  currentDocId = null;
124→  fileTitle = '';
125→  document.getElementById('topTitle').textContent = '大纲编辑器';
126→  document.getElementById('outlinePanel').innerHTML =
127→    '<div class="empty-state"><div class="empty-icon">📄</div>点击「导入 .md」或将文件拖放到窗口</div>';
128→  refreshMeta();
129→  loadDocList();
130→}
