132→// Drag & drop
133→document.addEventListener('dragenter',e=>{if(e.dataTransfer.types&&Array.from(e.dataTransfer.types).includes('Files'))document.body.classList.add('dragging');});
134→document.addEventListener('dragleave',e=>{if(!e.relatedTarget)document.body.classList.remove('dragging');});
135→document.addEventListener('dragover',e=>e.preventDefault());
136→document.addEventListener('drop',e=>{e.preventDefault();document.body.classList.remove('dragging');const f=e.dataTransfer.files&&e.dataTransfer.files[0];if(f)loadFile(f);});
137→
138→async function deleteDocument(id) {
139→  if (!confirm('确定删除这个文档吗？')) return;
140→  try {
