142→    if (currentDocId === id) { newDocument(); }
143→    showToast('已删除');
144→    loadDocList();
145→  } catch (e) {
146→    showToast('删除失败: ' + e.message, true);
147→  }
148→}
149→
150→// Init
151→loadDocList();
152→autoLoadFromUrl();
153→loadUserInfo();
154→</script>
