151→// ═══════════════════════════════════════════════════════════════════════
152→// PARSER
153→// ═══════════════════════════════════════════════════════════════════════
154→function parseOutline(text) {
155→  const lines = text.replace(/\r\n/g,'\n').replace(/\r/g,'\n').split('\n');
156→  const result = [];
157→  let act=null, chapter=null, scene=null;
158→  let summaryLines=[], bodyLines=[], detailLines=[], actNoteLines=[], inDetail=false;
159→
160→  function flush() {
161→    if (scene) {
162→      scene.summary = summaryLines.join('\n').trimEnd();
163→      scene.body    = bodyLines.join('\n').trimEnd();
164→      scene.detail  = detailLines.join('\n').trim();
165→    }
166→    if (act && !chapter) {
167→      act.notes = actNoteLines.join('\n').trim();
168→    }
169→    summaryLines=[]; bodyLines=[]; detailLines=[]; actNoteLines=[]; inDetail=false; scene=null;
170→  }
171→
172→  for (const raw of lines) {
173→    const line = raw.trim();
174→    if (line.startsWith('## ')&&!line.startsWith('### ')) {
175→      flush(); act={title:line.slice(3).trim(),chapters:[],open:true,notes:''}; chapter=null; result.push(act); continue;
176→    }
177→    if (line.startsWith('### ')) {
178→      if (act && !chapter) { act.notes = actNoteLines.join('\n').trim(); actNoteLines=[]; }
179→      flush(); if(act){chapter={title:line.slice(4).trim(),scenes:[],open:true};act.chapters.push(chapter);} continue;
180→    }
181→    const sm=line.match(/^\*\*(\d+[A-Za-z]+(?:\.\d+)?)[. ]\s*(.+?)\*\*/);
182→    if (sm&&chapter) {
183→      flush(); scene={id:sm[1],title:sm[2].trim(),summary:'',body:'',detail:''}; chapter.scenes.push(scene); continue;
184→    }
185→    if (act && !chapter && !scene) { actNoteLines.push(raw); continue; }
186→    if (!scene) continue;
187→    if (line.startsWith('<details>')) { inDetail=true; continue; }
188→    if (line==='</details>') { inDetail=false; continue; }
189→    if (inDetail) { detailLines.push(raw); continue; }
190→    if (raw.startsWith('> ') || raw==='>') {
191→      summaryLines.push(raw.startsWith('> ') ? raw.slice(2) : ''); continue;
192→    }
193→    if (!line.startsWith('#') && !line.startsWith('```')) bodyLines.push(raw);
194→  }
195→  flush(); return result;
196→}
