205→function renderOutline() {
206→  const panel = document.getElementById('outlinePanel');
207→  let html = '';
208→  acts.forEach(function(act, ai) {
209→    html += '<div class="act'+(act.open?'':' collapsed')+'" id="act-'+ai+'">';
210→    html += '<div class="act-header" onclick="toggleAct('+ai+');selectAct('+ai+')">'+chevron()+esc(act.title)+'</div>';
211→    html += '<div class="act-body'+(act.open?'':' hidden')+'">';
212→    act.chapters.forEach(function(ch, ci) {
213→      html += '<div class="chapter'+(ch.open?'':' collapsed')+'" id="ch-'+ai+'-'+ci+'">';
214→      html += '<div class="chapter-header" onclick="toggleChapter('+ai+','+ci+')">'+chevron()+esc(ch.title)+'</div>';
215→      html += '<div class="chapter-body'+(ch.open?'':' hidden')+'">';
216→      ch.scenes.forEach(function(sc) {
217→        const dotOn = sc.detail ? ' on' : '';
218→        const sel = sc.id === selectedId ? ' selected' : '';
219→        const displayText = sc.summary || sc.body;
220→        const body = displayText ? '<div class="scene-body-text" contenteditable="true" data-id="'+ea(sc.id)+'" onfocus="selectScene(\''+ea(sc.id)+'\')" onblur="onSummaryBlur(this)" onkeydown="handleBodyKey(event)">'+esc(displayText)+'</div>' : '';
221→        html += '<div class="scene-item'+sel+'" data-id="'+ea(sc.id)+'">';
222→        html += '<div class="scene-content">';
223→        html += '<div class="scene-title-row">';
224→        html += '<div class="scene-left"><div class="dot-btn" onclick="selectScene(\''+ea(sc.id)+'\')" title="查看原文"><div class="dot'+dotOn+'" data-dot="'+ea(sc.id)+'"></div></div><span class="scene-id">'+esc(sc.id)+'</span></div>';
225→        html += '<span class="scene-title-text" contenteditable="true" data-id="'+ea(sc.id)+'" data-field="title" onfocus="selectScene(\''+ea(sc.id)+'\')" onblur="onEditBlur(this)" onclick="event.stopPropagation()" onkeydown="handleTitleKey(event)">'+esc(sc.title)+'</span>';
226→        html += '</div>';
227→        html += body+'</div></div>';
228→      });
229→      html += '</div></div>';
230→    });
231→    html += '</div></div>';
232→  });
233→  panel.innerHTML = html;
234→}
