294→function expandLevel(){ if(viewLevel<2){viewLevel++;applyLevel();} }
295→function collapseLevel(){ if(viewLevel>0){viewLevel--;applyLevel();} }
296→function applyLevel(){
297→  const actsOpen = viewLevel>=1;
298→  const chaptersOpen = viewLevel>=2;
299→  acts.forEach(function(act,ai){
