383→async function loadDocList() {
384→  try {
385→    const docs = await apiFetch('/api/doc/list');
386→    const list = document.getElementById('docList');
387→    if (!docs || docs.length === 0) {
388→      list.innerHTML = '<div style="padding:12px;color:var(--text-muted);font-size:11px;text-align:center;">暂无文档</div>';
389→      return;
390→    }
391→    list.innerHTML = docs.map(d =>
392→      `<a class="doc-item${d.id === currentDocId ? ' active' : ''}" href="${buildDocUrl(d.id)}" onclick="event.preventDefault();openDocument(${d.id})" data-doc-id="${d.id}">
393→        ${esc(d.title || '无标题')}
394→        <div class="doc-item-time">${formatTime(d.updatedAt)}</div>
395→      </a>`
396→    ).join('');
397→  } catch (e) {
398→    console.warn('加载文档列表失败:', e);
399→  }
400→}
